<script setup lang="ts">
import { computed,onMounted } from 'vue'; import { useAuthStore } from '@/stores/auth'; import { useChatStore } from '@/stores/chat'; import { useHealthCasesStore } from '@/stores/healthCases'; import PriorityBadge from '@/components/health/PriorityBadge.vue'
const auth=useAuthStore(); const chat=useChatStore(); const cases=useHealthCasesStore(); onMounted(async()=>{await Promise.all([chat.cargarConversaciones(),cases.loadCases()])})
const active=computed(()=>cases.cases.filter(c=>!['CLOSED','RESOLVED'].includes(c.status)).length); const urgent=computed(()=>cases.cases.filter(c=>c.priority_level==='EMERGENCY').length); const pending=computed(()=>cases.pendingReview.length)
</script>
<template><div class="page"><div class="hero"><div><span>Bienvenida, {{auth.userName}}</span><h1>Tu acceso a salud, más claro y cercano.</h1><p>Describe una necesidad, encuentra servicios y conserva el seguimiento en un solo lugar.</p><router-link to="/app/chat" class="btn btn-primary">Iniciar orientación</router-link></div><div class="hero-icon">🌊✚</div></div><section class="stats"><article><span>💬</span><div><strong>{{chat.conversaciones.length}}</strong><small>Conversaciones</small></div></article><article><span>📋</span><div><strong>{{active}}</strong><small>Casos activos</small></div></article><article><span>🔴</span><div><strong>{{urgent}}</strong><small>Alertas detectadas</small></div></article><article><span>👩‍⚕️</span><div><strong>{{pending}}</strong><small>Revisión humana</small></div></article></section><section class="grid"><div class="card"><div class="card-header">Casos recientes</div><div class="card-body"><div v-if="!cases.cases.length" class="empty">Todavía no tienes casos. Inicia una orientación para crear el primero.</div><router-link v-for="item in cases.cases.slice(0,5)" :key="item.id" to="/app/casos" class="case-row"><div><strong>{{item.reason||'Caso de orientación'}}</strong><small>{{new Date(item.updated_at).toLocaleDateString('es-EC')}} · {{item.status}}</small></div><PriorityBadge :priority="item.priority_level"/></router-link></div></div><div class="card help"><div class="card-header">Accesos rápidos</div><div class="card-body"><router-link to="/app/servicios">📍 Buscar servicios</router-link><router-link to="/app/chat">🧠 Consultar al agente</router-link><router-link to="/app/perfil">♿ Ajustar accesibilidad</router-link><div class="warning">Ante una emergencia real, llama al ECU 911.</div></div></div></section></div></template>
